from dataclasses import dataclass
from enum import Enum

class SDKChangeType(str, Enum):
    PATCH        = "patch"         # bug fix, no API change
    MINOR        = "minor"         # new capability, backward compatible
    MAJOR        = "major"         # breaking changes possible
    MODEL_ALIAS  = "model_alias"   # SDK updates model alias (e.g. claude-3-5-sonnet-latest)

@dataclass
class SDKVersionChange:
    from_version: str
    to_version: str
    change_type: SDKChangeType
    changelog_notes: list[str]

    def touches_inference_path(self) -> bool:
        # All SDK changes touch inference — it is the SDK's primary purpose
        return True

    def requires_golden_set_eval(self) -> bool:
        # Run golden-set eval for minor/major/model_alias changes
        return self.change_type != SDKChangeType.PATCH

    def upgrade_track(self) -> str:
        if self.change_type == SDKChangeType.MAJOR:
            return "plan"        # 90d; breaking changes need sprint capacity
        if self.change_type in (SDKChangeType.MINOR, SDKChangeType.MODEL_ALIAS):
            return "maintain"    # 30d; routine window with golden-set eval
        return "maintain"        # patch: routine window, no golden-set eval needed

    def deploy_strategy(self) -> str:
        if self.change_type == SDKChangeType.MAJOR:
            return "blue_green"   # safest; keep old stack live until new is verified
        return "canary"           # 5% canary for minor/model_alias; rolling for patch

from dataclasses import dataclass, field

@dataclass
class MigrationItem:
    description: str
    affected_code_paths: list[str]
    migration_action: str
    test_coverage: str   # how to verify the migration is correct

@dataclass
class SDKMajorUpgradePlan:
    from_version: str
    to_version: str
    migration_guide_url: str
    items: list[MigrationItem] = field(default_factory=list)

    def estimate_sprint_days(self) -> float:
        """
        Rough estimate: 0.5 days per migration item plus
        1 day for full test run and golden-set eval.
        """
        return len(self.items) * 0.5 + 1.0

    def has_streaming_changes(self) -> bool:
        return any("stream" in item.description.lower() for item in self.items)

    def validation_steps(self) -> list[str]:
        steps = [
            "Apply all migration items from the guide",
            "Run full unit and integration test suite",
            "Run golden-set evaluation against staging",
        ]
        if self.has_streaming_changes():
            steps.append(
                "Run streaming-specific tests: verify all event types "
                "(message_start, content_block_start, content_block_delta, "
                "content_block_stop, message_delta, message_stop) parse correctly"
            )
        steps += [
            "Deploy to staging and run smoke tests",
            "Monitor staging for 24h before scheduling production window",
        ]
        return steps

from dataclasses import dataclass
from datetime import date, timedelta

@dataclass
class SDKSupportLifecycle:
    major_version: int
    general_availability: date
    end_of_active_support: date    # last date for new features
    end_of_security_support: date  # last date for security patches

    def days_until_eol(self, today: date) -> int:
        return (self.end_of_security_support - today).days

    def upgrade_urgency(self, today: date) -> str:
        days = self.days_until_eol(today)
        if days < 0:
            return "DEPRECATED: security patches no longer issued"
        if days < 60:
            return "CRITICAL: upgrade before end-of-security-support"
        if days < 180:
            return "HIGH: plan upgrade within next quarter"
        return "LOW: on supported version"

    def latest_upgrade_start_date(self, today: date) -> date:
        """
        Returns the latest date by which an SDK major upgrade should START
        (allowing 90d for a major upgrade project) to complete before EOL.
        """
        return self.end_of_security_support - timedelta(days=90)

    def should_start_upgrade_project(self, today: date) -> bool:
        return today >= self.latest_upgrade_start_date(today)
